import sys

def nth_palindrome(n):
    if n == 1:
        return 0
    n -= 2  # Adjust for 0 and 1-digit palindromes

    length = 1
    while True:
        half_length = (length + 1) // 2
        count = 9 * 10 ** (half_length - 1)
        if n < count:
            break
        n -= count
        length += 1

    half = 10 ** (half_length - 1) + n
    half_str = str(half)
    if length % 2 == 0:
        return int(half_str + half_str[::-1])
    else:
        return int(half_str + half_str[-2::-1])

def main():
    n = int(sys.stdin.readline())
    print(nth_palindrome(n))

if __name__ == "__main__":
    main()
